-- =============================================
-- Library Management System - Database Init Script
-- =============================================

-- Ensure client connection uses utf8mb4 (prevents "Data too long" errors on Chinese text)
SET NAMES utf8mb4;
SET CHARACTER SET utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- Drop and recreate database for clean initialization
DROP DATABASE IF EXISTS library_db;
CREATE DATABASE library_db DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE library_db;

-- ---------------------------------------------
-- 1. Role table (RBAC)
-- ---------------------------------------------
DROP TABLE IF EXISTS `sys_role`;
CREATE TABLE `sys_role` (
    `id`          BIGINT       NOT NULL AUTO_INCREMENT COMMENT '角色ID',
    `role_name`   VARCHAR(100) NOT NULL COMMENT '角色名称',
    `role_code`   VARCHAR(100) NOT NULL COMMENT '角色编码',
    `description` VARCHAR(200) DEFAULT NULL COMMENT '描述',
    `status`      TINYINT      DEFAULT 1 COMMENT '状态: 1启用 0禁用',
    `create_time` DATETIME     DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
    `update_time` DATETIME     DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
    `deleted`     TINYINT      DEFAULT 0 COMMENT '逻辑删除',
    PRIMARY KEY (`id`),
    UNIQUE KEY `uk_role_code` (`role_code`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='系统角色表';

-- ---------------------------------------------
-- 2. User (Reader) table
-- ---------------------------------------------
DROP TABLE IF EXISTS `sys_user`;
CREATE TABLE `sys_user` (
    `id`          BIGINT       NOT NULL AUTO_INCREMENT COMMENT '用户ID',
    `username`    VARCHAR(50)  NOT NULL COMMENT '用户名',
    `password`    VARCHAR(200) NOT NULL COMMENT '密码(BCrypt)',
    `real_name`   VARCHAR(50)  DEFAULT NULL COMMENT '真实姓名',
    `gender`      TINYINT      DEFAULT 0 COMMENT '性别: 0未知 1男 2女',
    `phone`       VARCHAR(20)  DEFAULT NULL COMMENT '手机号',
    `email`       VARCHAR(100) DEFAULT NULL COMMENT '邮箱',
    `avatar`      VARCHAR(255) DEFAULT NULL COMMENT '头像URL',
    `role_id`     BIGINT       DEFAULT NULL COMMENT '角色ID',
    `reader_no`   VARCHAR(30)  DEFAULT NULL COMMENT '读者证号',
    `status`      TINYINT      DEFAULT 1 COMMENT '状态: 1正常 0冻结',
    `create_time` DATETIME     DEFAULT CURRENT_TIMESTAMP COMMENT '注册时间',
    `update_time` DATETIME     DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
    `deleted`     TINYINT      DEFAULT 0 COMMENT '逻辑删除',
    PRIMARY KEY (`id`),
    UNIQUE KEY `uk_username` (`username`),
    UNIQUE KEY `uk_reader_no` (`reader_no`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='系统用户(读者)表';

-- ---------------------------------------------
-- 3. Book Category table
-- ---------------------------------------------
DROP TABLE IF EXISTS `book_category`;
CREATE TABLE `book_category` (
    `id`          BIGINT       NOT NULL AUTO_INCREMENT COMMENT '分类ID',
    `name`        VARCHAR(100) NOT NULL COMMENT '分类名称',
    `parent_id`   BIGINT       DEFAULT 0 COMMENT '父分类ID(0为顶级)',
    `sort`        INT          DEFAULT 0 COMMENT '排序',
    `description` VARCHAR(200) DEFAULT NULL COMMENT '描述',
    `create_time` DATETIME     DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
    `update_time` DATETIME     DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
    `deleted`     TINYINT      DEFAULT 0 COMMENT '逻辑删除',
    PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='图书分类表';

-- ---------------------------------------------
-- 4. Book table
-- ---------------------------------------------
DROP TABLE IF EXISTS `book`;
CREATE TABLE `book` (
    `id`           BIGINT        NOT NULL AUTO_INCREMENT COMMENT '图书ID',
    `isbn`         VARCHAR(20)   NOT NULL COMMENT 'ISBN号',
    `title`        VARCHAR(200)  NOT NULL COMMENT '书名',
    `author`       VARCHAR(100)  DEFAULT NULL COMMENT '作者',
    `publisher`    VARCHAR(100)  DEFAULT NULL COMMENT '出版社',
    `publish_date` DATE          DEFAULT NULL COMMENT '出版日期',
    `category_id`  BIGINT        DEFAULT NULL COMMENT '分类ID',
    `price`        DECIMAL(10,2) DEFAULT NULL COMMENT '定价',
    `location`     VARCHAR(100)  DEFAULT NULL COMMENT '馆藏位置',
    `total_count`  INT           DEFAULT 1 COMMENT '馆藏总数',
    `available_count` INT        DEFAULT 1 COMMENT '可借数量',
    `description`  TEXT          DEFAULT NULL COMMENT '内容简介',
    `cover_url`    VARCHAR(255)  DEFAULT NULL COMMENT '封面URL',
    `status`       TINYINT       DEFAULT 1 COMMENT '状态: 1在馆 0下架',
    `create_time`  DATETIME      DEFAULT CURRENT_TIMESTAMP COMMENT '入库时间',
    `update_time`  DATETIME      DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
    `deleted`      TINYINT       DEFAULT 0 COMMENT '逻辑删除',
    PRIMARY KEY (`id`),
    UNIQUE KEY `uk_isbn` (`isbn`),
    KEY `idx_title` (`title`),
    KEY `idx_category` (`category_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='图书信息表';

-- ---------------------------------------------
-- 5. Borrow Record table
-- ---------------------------------------------
DROP TABLE IF EXISTS `borrow_record`;
CREATE TABLE `borrow_record` (
    `id`             BIGINT        NOT NULL AUTO_INCREMENT COMMENT '借阅ID',
    `record_no`      VARCHAR(30)   NOT NULL COMMENT '借阅单号',
    `user_id`        BIGINT        NOT NULL COMMENT '读者ID',
    `book_id`        BIGINT        NOT NULL COMMENT '图书ID',
    `borrow_date`    DATETIME      NOT NULL COMMENT '借阅时间',
    `due_date`       DATETIME      NOT NULL COMMENT '应还时间',
    `return_date`    DATETIME      DEFAULT NULL COMMENT '实际归还时间',
    `status`         TINYINT       DEFAULT 0 COMMENT '状态: 0借阅中 1已归还 2已逾期',
    `renew_count`    INT           DEFAULT 0 COMMENT '续借次数',
    `fine_amount`    DECIMAL(10,2) DEFAULT 0.00 COMMENT '罚款金额',
    `fine_status`    TINYINT       DEFAULT 0 COMMENT '罚款状态: 0无罚款 1待缴 2已缴',
    `remark`         VARCHAR(500)  DEFAULT NULL COMMENT '备注',
    `create_time`    DATETIME      DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
    `update_time`    DATETIME      DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
    `deleted`        TINYINT       DEFAULT 0 COMMENT '逻辑删除',
    PRIMARY KEY (`id`),
    UNIQUE KEY `uk_record_no` (`record_no`),
    KEY `idx_user` (`user_id`),
    KEY `idx_book` (`book_id`),
    KEY `idx_status` (`status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='借阅记录表';

